fetch('https://www.e-solat.gov.my/index.php?r=esolatApi/takwimsolat&period=today&zone=SGR01').then(function(r){return r.json()}).then(function(data){var t=data.prayerTime[0];var f=function(s){var a=s.split(':');var h=parseInt(a[0]);return(h>12?h-12:h)+':'+a[1]+(h>=12?' PM':' AM')};var p=t.date.split('-');var m={Jan:0,Feb:1,Mar:2,Apr:3,May:4,Jun:5,Jul:6,Aug:7,Sep:8,Oct:9,Nov:10,Dec:11};var d=new Date(p[2],m[p[1]],parseInt(p[0])).toLocaleDateString('ms-MY',{weekday:'long',day:'numeric',month:'long',year:'numeric'});document.getElementById('solatBanner').innerHTML='<div class="solatBanner-inner"><span class="solatBanner-title">Waktu Solat: Selangor<br>'+d+'</span><span>Imsak<br>'+f(t.imsak)+'</span><span>Subuh<br>'+f(t.fajr)+'</span><span>Syuruk<br>'+f(t.syuruk)+'</span><span>Duha<br>'+f(t.dhuha)+'</span><span>Zohor<br>'+f(t.dhuhr)+'</span><span>Asar<br>'+f(t.asr)+'</span><span>Maghrib<br>'+f(t.maghrib)+'</span><span>Isyak<br>'+f(t.isha)+'</span></div>'});